import{_ as a,o as t,c as r,ag as o}from"./chunks/framework.DXGyWiRo.js";const h=JSON.parse('{"title":"Open-source WebRTC Projects","description":"Credit: https://medevel.com/13-os-webrtc-server/","frontmatter":{"description":"Credit: https://medevel.com/13-os-webrtc-server/"},"headers":[],"relativePath":"software-engineering/webrtc/opensource-webrtc-projects.md","filePath":"software-engineering/webrtc/opensource-webrtc-projects.md"}'),i={name:"software-engineering/webrtc/opensource-webrtc-projects.md"};function n(s,e,l,d,p,u){return t(),r("div",null,[...e[0]||(e[0]=[o('<h1 id="open-source-webrtc-projects" tabindex="-1">Open-source WebRTC Projects <a class="header-anchor" href="#open-source-webrtc-projects" aria-label="Permalink to &quot;Open-source WebRTC Projects&quot;">​</a></h1><h2 id="top-13-open-source-webrtc-projects-to-build-video-conferencing-and-calling-app" tabindex="-1">Top 13 open-source WebRTC projects to build Video conferencing and calling app <a class="header-anchor" href="#top-13-open-source-webrtc-projects-to-build-video-conferencing-and-calling-app" aria-label="Permalink to &quot;Top 13 open-source WebRTC projects to build Video conferencing and calling app&quot;">​</a></h2><p>WebRTC is an open-source framework that enables real-time communications for the web through your web browser.</p><p>In contrast, it is the basic protocol that allows web apps and websites to capture and stream videos and audio and exchange data between web browsers.</p><p>WebRTC was first created by Google to make peer-to-peer communication possible for web browsers and mobile apps, leading to dozens of video and audio communication apps that we use every day.</p><p>It is a free and open-source project, which means it does not require any cost to run and use it</p><p>Another Advantage for WebRTC is it is fast, and because, unlike UDP-based apps, it does not require any handshake between the client and the server.</p><p>Some may consider WebRTC standard not safe or secure because it exposes the real public IP of the user, therefore if you are using WebRTC with Google Chrome or Mozilla Firefox you are not anonymous.</p><p>In this article, you will find the best free, open-source WebRTC libraries and frameworks to build WebRTC-based projects.</p><h3 id="_1-kurento" tabindex="-1">1- Kurento <a href="#1kurento" id="1kurento"></a> <a class="header-anchor" href="#_1-kurento" aria-label="Permalink to &quot;1- Kurento &lt;a href=&quot;#1kurento&quot; id=&quot;1kurento&quot;&gt;&lt;/a&gt;&quot;">​</a></h3><p><a href="https://github.com/Kurento" target="_blank" rel="noreferrer">Kurento</a> is a free, open-source WebRTC media server with a rich API set for building rich video applications for web, and mobile.</p><p>Kurento is written with C/C++ and uses several GStreamer functions. It is started as a project at Rey Juan Carlos University in Madrid in 2010 then released as an open-source project.</p><p><strong>Kurento&#39;s features</strong></p><ul><li>Networked streaming protocols, including HTTP, RTP, and WebRTC.</li><li>Group communications (MCUs and SFUs functionality) support both media mixing and media routing/dispatching.</li><li>Generic support for the computational vision and augmented reality filters.</li><li>Media storage supporting writing operations for WebM and MP4 and playing in all formats supported by GStreamer.</li><li>Automatic media transcoding between any of the codecs supported by GStreamer including VP8, H.264, H.263, AMR, OPUS, Speex, G.711, etc.</li></ul><p>Kurento is licensed under Apache 2.0 open-source license.</p><h3 id="_2-ant-media-server" tabindex="-1">2- Ant Media Server <a href="#2ant-media-server" id="2ant-media-server"></a> <a class="header-anchor" href="#_2-ant-media-server" aria-label="Permalink to &quot;2- Ant Media Server &lt;a href=&quot;#2ant-media-server&quot; id=&quot;2ant-media-server&quot;&gt;&lt;/a&gt;&quot;">​</a></h3><p><a href="https://github.com/ant-media/ant-media-server" target="_blank" rel="noreferrer">Ant Media Server</a> is a media server for building real-time video and audio communication tools with low latency streaming.</p><p>In addition to its support to WebRTC, Ant Media also supports many protocols like CMAF, HLS, RTMP, RTSP, and many others.</p><p>Ant Media Server is highly scalable, with 0.5 latency, and can be installed on-premise or on-cloud.</p><p>Ant Media comes with two editions, an enterprise edition with a commercial license, and a free, open-source community edition.</p><p><strong>Features for Ant Media Server (Community Edition)</strong></p><ul><li>Ultra-Low Latency Adaptive One to Many WebRTC Live Streaming in <strong>Enterprise Edition</strong></li><li>Adaptive Bitrate for Live Streams (WebRTC, MP4, HLS) in <strong>Enterprise Edition</strong></li><li>VP8 &amp; H264 Support in WebRTC <strong>Enterprise Edition</strong></li><li>Data Channel Support in WebRTC <strong>Enterprise Edition</strong></li><li>Horizontal(Clustering) and Vertical Scaling <strong>Enterprise Edition</strong></li><li>SFU in One to Many WebRTC Streams in <strong>Enterprise Edition</strong></li><li>Live Stream Publishing from RTMP to WebRTC <strong>Enterprise Edition</strong></li><li>RTMP Ingesting</li><li>WebRTC to RTMP Adapter</li><li>IP Camera Support</li><li>Recording Live Streams (MP4 and HLS)</li><li>Restream to Social Media Simultaneously(Facebook and YouTube in <strong>Enterprise Edition</strong>)</li><li>One-Time Token Control in <strong>Enterprise Edition</strong></li><li>Object Detection in <strong>Enterprise Edition</strong></li><li>Ant Media Server is bundled with Android, iOS, and JavaScript SDKs. SDKs are available for free.</li></ul><h3 id="_3-open-easyrtc" tabindex="-1">3- Open-EasyRTC <a href="#3open-easyrtc" id="3open-easyrtc"></a> <a class="header-anchor" href="#_3-open-easyrtc" aria-label="Permalink to &quot;3- Open-EasyRTC &lt;a href=&quot;#3open-easyrtc&quot; id=&quot;3open-easyrtc&quot;&gt;&lt;/a&gt;&quot;">​</a></h3><p><a href="https://github.com/open-easyrtc/open-easyrtc" target="_blank" rel="noreferrer">Open-EasyRTC</a> is a free, open-source WebRTC toolkit for building real-time media-rich web and mobile apps.</p><p>Open-EasyRTC offers developer-friendly documentation, with several code samples and demos to help developers create usable apps in no time.</p><p>Open-EasyRTC is a fork of the primary <a href="http://easyrtc.com/" target="_blank" rel="noreferrer">EasyRTC</a> project with its server and client APIs, and HTML5/ JavaScript demos released under the BSD 2 License.</p><h3 id="_4-openvidu" tabindex="-1">4- openVidu <a href="#4openvidu" id="4openvidu"></a> <a class="header-anchor" href="#_4-openvidu" aria-label="Permalink to &quot;4- openVidu &lt;a href=&quot;#4openvidu&quot; id=&quot;4openvidu&quot;&gt;&lt;/a&gt;&quot;">​</a></h3><p><a href="https://openvidu.io/" target="_blank" rel="noreferrer">openVidu</a> is an open-source (Apache License v2), development platform for building video conference and video calling applications.</p><p>openVidu comes with full WebRTC encryption support and works seamlessly with all popular JavaScript frameworks like React, Angular, TypeScript, Vue.js, and Ionic.</p><p>If you like building your apps with REST-API, then you are lucky as openVidu got you covered with a developer-friendly REST-API.</p><h3 id="_5-galene" tabindex="-1">5- Galene <a href="#5galene" id="5galene"></a> <a class="header-anchor" href="#_5-galene" aria-label="Permalink to &quot;5- Galene &lt;a href=&quot;#5galene&quot; id=&quot;5galene&quot;&gt;&lt;/a&gt;&quot;">​</a></h3><p><a href="https://github.com/jech/galene" target="_blank" rel="noreferrer">Galene</a> is a feature-rich free, open-source videoconference server that is easy to <a href="https://galene.org/" target="_blank" rel="noreferrer">install</a>, deploy, and use.</p><p>Here are its current features:</p><ul><li>redistribution of arbitrary numbers of audio and video streams;</li><li>text chat;</li><li>recording to disk;</li><li>user statuses (&quot;raise hand&quot;, etc.; not yet used by the default client);</li><li>choice of audio and video codecs (full functionality for VP8, VP9, and H.264, preliminary support for AV1);</li><li>Simulcast;</li><li>Scalable Video Coding (SVC) for VP8 and VP9;</li><li>NACK-based loss recovery, in both the client-server and server → client directions;</li><li>PLI-based repair;</li><li>automatic restarting of failed flows (on ICE failure);</li><li>congestion control in the server → client direction (both loss-based and using REMB indications);</li><li>congestion control in the client → server direction (loss-based, partial REMB support);</li><li>dynamic tuning of buffer sizes depending on the clients&#39; RTT;</li><li>hashed passwords;</li><li>built-in TURN server.</li></ul><h3 id="_6-saltyrtc" tabindex="-1">6- SaltyRTC <a href="#6saltyrtc" id="6saltyrtc"></a> <a class="header-anchor" href="#_6-saltyrtc" aria-label="Permalink to &quot;6- SaltyRTC &lt;a href=&quot;#6saltyrtc&quot; id=&quot;6saltyrtc&quot;&gt;&lt;/a&gt;&quot;">​</a></h3><p><a href="https://saltyrtc.org/" target="_blank" rel="noreferrer">SaltyRTC</a> is an end-to-end encryption protocol for building encrypted WebRTC or ORTC peer-to-peer communication apps.</p><p>The project offers a long list of implementation samples and demos which help to put developers on the right track to build their encrypted WebRTC tools.</p><h3 id="_7-janus" tabindex="-1">7- Janus <a href="#7janus" id="7janus"></a> <a class="header-anchor" href="#_7-janus" aria-label="Permalink to &quot;7- Janus &lt;a href=&quot;#7janus&quot; id=&quot;7janus&quot;&gt;&lt;/a&gt;&quot;">​</a></h3><p><a href="https://janus.conf.meetecho.com/" target="_blank" rel="noreferrer">Janus</a> is a general-purpose WebRTC server for building WebRTC-based apps like video calling, conferencing, and group video chats solutions.</p><p>Janus has a small footprint with low latency and comes with many code samples and demos with developer-friendly documentation that help developers install, implement and run apps in no time.</p><p><a href="https://github.com/meetecho/janus-gateway" target="_blank" rel="noreferrer">Janus</a> is released under GNU General Public License Version 3 (GPLv3).</p><h3 id="_8-ion-media-server" tabindex="-1">8- ion media server <a href="#8ion-media-server" id="8ion-media-server"></a> <a class="header-anchor" href="#_8-ion-media-server" aria-label="Permalink to &quot;8- ion media server &lt;a href=&quot;#8ion-media-server&quot; id=&quot;8ion-media-server&quot;&gt;&lt;/a&gt;&quot;">​</a></h3><p><a href="https://github.com/pion/ion" target="_blank" rel="noreferrer">ION</a> is an open-source distributed real-time communication system built in pure Go programming language. It uses PION/ Flutter-WebRTC library.</p><p>The project is released and licensed under MIT License.</p><h3 id="_9-mediasoup" tabindex="-1">9- MediaSoup <a href="#9mediasoup" id="9mediasoup"></a> <a class="header-anchor" href="#_9-mediasoup" aria-label="Permalink to &quot;9- MediaSoup &lt;a href=&quot;#9mediasoup&quot; id=&quot;9mediasoup&quot;&gt;&lt;/a&gt;&quot;">​</a></h3><p><a href="https://mediasoup.org/" target="_blank" rel="noreferrer">MediaSoup</a> is a rich toolkit for building WebRTC video conferencing apps with its open-source supported Node.js and Rust servers.</p><p>It can be used to create group video chat apps or one-to-many conferencing apps with full RTP streaming support.</p><p>MediaSoup comes with low-latency support, and Rust/ Node.JS servers. It supports data message exchange (via WebRTC DataChannels, SCTP over plain UDP, and direct termination in Node.js/Rust). It also offers built-in Simulcast and SVC support.</p><ul><li>ECMAScript 6/Idiomatic Rust low-level API.</li><li>Multi-stream: multiple audio/video streams over a single ICE + DTLS transport.</li><li>IPv6 ready.</li><li>ICE / DTLS / RTP / RTCP over UDP and TCP.</li><li>Simulcast and SVC support.</li><li>Congestion control.</li><li>Sender and receiver bandwidth estimation with spatial/temporal layers distribution algorithm.</li><li>Data message exchange (via WebRTC DataChannels, SCTP over plain UDP, and direct termination in Node.js/Rust).</li><li>Extremely powerful (media worker thread/subprocess coded in C++ on top of libuv).</li></ul><p>Here is a sample project that uses <a href="https://github.com/edumeet/edumeet" target="_blank" rel="noreferrer">MediaSoup</a>.</p><h3 id="_10-ovenmediaengine" tabindex="-1">10- OvenMediaEngine <a href="#10ovenmediaengine" id="10ovenmediaengine"></a> <a class="header-anchor" href="#_10-ovenmediaengine" aria-label="Permalink to &quot;10- OvenMediaEngine &lt;a href=&quot;#10ovenmediaengine&quot; id=&quot;10ovenmediaengine&quot;&gt;&lt;/a&gt;&quot;">​</a></h3><p><a href="https://www.ovenmediaengine.com/ome" target="_blank" rel="noreferrer">OvenMediaEngine</a> is an open-source streaming server with a low-latency rate for building real-time communication solutions.</p><p>OvenMediaEngine supports many communication inputs/ outputs protocols and comes with media encoders which makes it ideal for building enterprise video/ audio conferences and calls.</p><p>The supported protocols include WebRTC, RTMP, SRT, RTSP, and TS.</p><p>OvenMediaEngine comes with a built-in embedded live transcoder that supports VP8, H264, Opus, AAC, and Pass-Through.</p><h3 id="_11-temasys" tabindex="-1">11- Temasys <a href="#11temasys" id="11temasys"></a> <a class="header-anchor" href="#_11-temasys" aria-label="Permalink to &quot;11- Temasys &lt;a href=&quot;#11temasys&quot; id=&quot;11temasys&quot;&gt;&lt;/a&gt;&quot;">​</a></h3><p><a href="https://temasys.github.io/" target="_blank" rel="noreferrer">Temasys</a> project offers various WebRTC-based tools for building video conferencing and calling apps for the enterprise using the SkylinkJS Library.</p><p>The repo collection contains several demos and sample code that uses several technologies like Swift, Objective-C, React, C++, Java, and Android.</p><p>If you are planning or building WebRTC-based apps, then Temasys is a must-check project.</p><h3 id="_12-jscommunicator" tabindex="-1">12- JSCommunicator <a href="#12jscommunicator" id="12jscommunicator"></a> <a class="header-anchor" href="#_12-jscommunicator" aria-label="Permalink to &quot;12- JSCommunicator &lt;a href=&quot;#12jscommunicator&quot; id=&quot;12jscommunicator&quot;&gt;&lt;/a&gt;&quot;">​</a></h3><p><a href="https://jscommunicator.org/" target="_blank" rel="noreferrer">JSCommunicator</a> is JavaScript-based, free, open-source (GPL v2.0) tool developed in pure web technologies (HTML, CSS, and JavaScript).</p><p>JSCommunicator is a WebRTC tool that uses SIP protocol over WebSockets.</p><p>The project works seamlessly with web apps and can be embedded with any CMS like WordPress and Drupal.</p><p>You can obtain the source code and run it, or customize it for personal and commercial use.</p><h3 id="_13-peerjs-server-and-library" tabindex="-1">13- PeerJS Server and Library <a href="#13peerjs-server-and-library" id="13peerjs-server-and-library"></a> <a class="header-anchor" href="#_13-peerjs-server-and-library" aria-label="Permalink to &quot;13- PeerJS Server and Library &lt;a href=&quot;#13peerjs-server-and-library&quot; id=&quot;13peerjs-server-and-library&quot;&gt;&lt;/a&gt;&quot;">​</a></h3><p><a href="https://peerjs.com/" target="_blank" rel="noreferrer">PeerJS</a> Library wraps the browser&#39;s WebRTC implementation with an easy-to-use JavaScript API to build real-time peer-to-peer video and audio calling apps.</p><p>Both PeerJS client and server are free and open-source for anyone to download, install, run and build video/ audio apps.</p><p>PeerJS works well with other JavaScript frameworks like React, Angular, Vue, Meteor, Ionic, and others.</p><h3 id="to-sum-up" tabindex="-1">To sum up <a href="#to-sum-up" id="to-sum-up"></a> <a class="header-anchor" href="#to-sum-up" aria-label="Permalink to &quot;To sum up &lt;a href=&quot;#to-sum-up&quot; id=&quot;to-sum-up&quot;&gt;&lt;/a&gt;&quot;">​</a></h3><p>WebRTC or Web Real-Time Communication is the primary cornerstone of what powers most video conferencing and video calling apps.</p><p>Here, we listed the best open-source WebRTC projects for developers to create cool video conferencing tools and apps. If you know of any open-source WebRTC library or project that we did not mention here, let us know.</p>',71)])])}const m=a(i,[["render",n]]);export{h as __pageData,m as default};
